<div class="container">
    <div id="corrected-progress-bar" class="progress-bar">0%</div>
    <p id="corrected-progress-text">Progress: 0%</p>
</div>

<script>
    // Shared state for buggy implementation
    let buggyProgress = 0;

    // Buggy implementation
    function updateBuggyProgress(percent) {
        setTimeout(() => {
            buggyProgress += percent;
            document.getElementById('buggy-progress-bar').style.width = `${buggyProgress}%`;
            document.getElementById('buggy-progress-text').innerText = `Progress: ${buggyProgress}%`;
            if (buggyProgress > 100) {
                console.error('Buggy progress exceeded 100%');
            }
        }, 100); // Simulate some delay
    }

    // Concurrent tasks for buggy implementation
    Promise.all([
        updateBuggyProgress(30),
        updateBuggyProgress(40),
        updateBuggyProgress(30)
    ]).then(() => {
        console.log('Buggy implementation completed');
    });

    // Corrected implementation using atomic updates
    let correctedProgress = 0;
    let updateLock = false;

    function updateCorrectedProgress(percent) {
        return new Promise(resolve => {
            if (updateLock) {
                // If an update is in progress, queue the update
                setTimeout(() => {
                    updateCorrectedProgress(percent).then(resolve);
                }, 10);
                return;
            }
            updateLock = true;
            setTimeout(() => {
                correctedProgress = Math.min(correctedProgress + percent, 100);
                document.getElementById('corrected-progress-bar').style.width = `${correctedProgress}%`;
                document.getElementById('corrected-progress-text').innerText = `Progress: ${correctedProgress}%`;
                updateLock = false;
                resolve();
            }, 100); // Simulate some delay
        });
    }

    // Concurrent tasks for corrected implementation
    Promise.all([
        updateCorrectedProgress(30),
        updateCorrectedProgress(40),
        updateCorrectedProgress(30)
    ]).then(() => {
        console.log('Corrected implementation completed');
    });
</script>

